mber.","index":285,"end_time":768.34,"speaker_id":3,"start_time":765.54,"speaker_name":"Matthew Look"},{"text":"Oh, sorry.","index":286,"end_time":769.82,"speaker_id":4,"start_time":769.14,"speaker_name":"Lindsay Hall"},{"text":"I was trying to send it to you.","index":287,"end_time":771.02,"speaker_id":4,"start_time":769.82,"speaker_name":"Lindsay Hall"},{"text":"Yeah, I can pull it.","index":288,"end_time":772.74,"speaker_id":1,"start_time":771.02,"speaker_name":"Ryan Fisher"},{"text":"216.","index":289,"end_time":774.5,"speaker_id":1,"start_time":773.78,"speaker_name":"Ryan Fisher"},{"text":"Hold on a second.","index":290,"end_time":776.1,"speaker_id":1,"start_time":775.3,"speaker_name":"Ryan Fisher"},{"text":"786, 781-0575.","index":291,"end_time":783.29,"speaker_id":4,"start_time":778.02,"speaker_name":"Lindsay Hall"},{"text":"Stay right there for a second too.","index":292,"end_time":784.89,"speaker_id":3,"start_time":783.53,"speaker_name":"Matthew Look"},{"text":"0575.","index":293,"end_time":786.09,"speaker_id":1,"start_time":784.89,"speaker_name":"Ryan Fisher"},{"text":"Thanks.","index":294,"end_time":788.57,"speaker_id":1,"start_time":788.09,"speaker_name":"Ryan Fisher"},{"text":"Stay right there just for another second.","index":295,"end_time":791.85,"speaker_id":3,"start_time":790.41,"speaker_name":"Matthew Look"},{"text":"Oh, hang on.","index":296,"end_time":801.13,"speaker_id":3,"start_time":799.13,"speaker_name":"Matthew Look"},{"text":"Edsi us dot.","index":297,"end_time":807.86,"speaker_id":3,"start_time":805.46,"speaker_name":"Matthew Look"},{"text":"All right, I''m good, thanks.","index":298,"end_time":824.42,"speaker_id":3,"start_time":823.22,"speaker_name":"Matthew Look"},{"text":"I got no emails either.","index":299,"end_time":826.58,"speaker_id":3,"start_time":825.22,"speaker_name":"Matthew Look"},{"text":"Did Kurt called.","index":300,"end_time":838.59,"speaker_id":1,"start_time":837.55,"speaker_name":"Ryan Fisher"},{"text":"And got voicemail