ker_name":"Gab"},{"text":"But Christina, if you want to go ahead without me and just record it and we can store it somewhere where we can find it, that''s fine.","index":311,"end_time":949.6,"speaker_id":2,"start_time":943.36,"speaker_name":"Gab"},{"text":"Okay.","index":312,"end_time":950.68,"speaker_id":3,"start_time":950.24,"speaker_name":"Christina Bila"},{"text":"That works.","index":313,"end_time":951.28,"speaker_id":3,"start_time":950.68,"speaker_name":"Christina Bila"},{"text":"Yeah, that works.","index":314,"end_time":954.16,"speaker_id":3,"start_time":953.2,"speaker_name":"Christina Bila"},{"text":"Okay, cool.","index":315,"end_time":956.08,"speaker_id":2,"start_time":954.48,"speaker_name":"Gab"},{"text":"I''m excited to see the designs.","index":316,"end_time":958.56,"speaker_id":2,"start_time":956.64,"speaker_name":"Gab"},{"text":"Yeah, yeah, they''re looking really good.","index":317,"end_time":961.52,"speaker_id":0,"start_time":959.12,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, they''re really nice.","index":318,"end_time":963.44,"speaker_id":4,"start_time":962.08,"speaker_name":"Igor Zagradjanin"},{"text":"Can''t wait.","index":319,"end_time":965.18,"speaker_id":3,"start_time":964.62,"speaker_name":"Christina Bila"},{"text":"And, yeah, finally your.","index":320,"end_time":968.94,"speaker_id":4,"start_time":966.22,"speaker_name":"Igor Zagradjanin"},{"text":"Plan Portal.","index":321,"end_time":971.58,"speaker_id":4,"start_time":970.54,"speaker_name":"Igor Zagradjanin"},{"text":"So, yeah.","index":322,"end_time":976.46,"speaker_id":4,"start_time":975.82,"speaker_name":"Igor Zagradjanin"},{"text":"Basically, yeah, yeah, just.","index":323,"end_time":981.66,"speaker_id":4,"start_time":978.7,"speaker_name":"Igor Zagradjanin"},{"text":"Yeah, designs.","index":324,"end_time":982.94,"speaker_id":4,"start_time":981.82,"speaker_name":"Igor Zagradjanin"},{"text":"And we''re gonna manage the edits for the episode.","index":325,"end_time":990.55,"speaker_id":